update dda_programmes
set contenu = jsonb_set(
  contenu,
  '{sections}',
  (
    select jsonb_agg(
      case when m.val is not null
      then jsonb_set(elem, '{questions}', (elem->'questions') || m.val)
      else elem end
    )
    from jsonb_array_elements(contenu->'sections') elem
    left join jsonb_each($map${"evaluation_2": [{"q": "Vendre un contrat d'assurance sans recueil de besoin préalable est-il conforme à la réglementation ?", "opts": ["Oui, si la vente aboutit", "Non, ce n'est pas conforme", "Cela dépend uniquement du prix du contrat"], "correct": 1}, {"q": "Un client qui découvre après coup une exclusion non présentée clairement :", "opts": ["Ne s'en soucie généralement pas", "Perd durablement confiance dans le conseiller", "Est légalement tenu de l'accepter"], "correct": 1}, {"q": "Au téléphone, en l'absence de langage corporel visible, quels éléments deviennent proportionnellement plus déterminants ?", "opts": ["Le ton, le débit et les silences", "La tenue vestimentaire", "La couleur du bureau du conseiller"], "correct": 0}, {"q": "Un conseiller qui cède à une tension commerciale en proposant une garantie inadaptée :", "opts": ["Fait preuve de bonne gestion de la relation client", "Manque à son devoir de conseil", "Applique la charte de déontologie correctement"], "correct": 1}, {"q": "La gestion du consentement en amont d'une campagne de prospection particuliers doit anticiper :", "opts": ["L'entrée en vigueur de la loi n°2025-594 le 11 août 2026", "La loi Hamon uniquement", "Aucune évolution réglementaire particulière"], "correct": 0}, {"q": "Le tunnel de vente de S@FE peut s'interrompre avant la signature par :", "opts": ["Une redirection tracée ou une ressaisie manuelle", "L'annulation systématique du dossier", "Une facturation anticipée"], "correct": 0}, {"q": "Le cycle de vente court concerne typiquement :", "opts": ["Les particuliers et produits standards (PNO, santé animale)", "Les risques professionnels complexes", "Toujours les plus gros contrats"], "correct": 0}, {"q": "Une checklist de préparation d'entretien s'appuie notamment sur :", "opts": ["Le SIRET auto-complété et l'historique CRM", "L'improvisation totale", "La météo du jour du rendez-vous"], "correct": 0}, {"q": "Un client qui évoque une cyberattaque récente chez un confrère, sans demande explicite, exprime :", "opts": ["Rien de particulier à explorer", "Un signal de besoin potentiel sur les garanties Cyber+RCP", "Une objection à traiter immédiatement"], "correct": 1}, {"q": "L'argumentaire commercial structuré caractéristique → avantage → bénéfice permet de :", "opts": ["Traduire une caractéristique technique en bénéfice concret pour le client", "Remplacer la remise de l'IPID", "Éviter de mentionner les exclusions"], "correct": 0}, {"q": "Omettre ou minorer les exclusions les plus significatives d'un contrat lors de la présentation constitue :", "opts": ["Une pratique commerciale acceptable si la vente aboutit", "Une insuffisance de conseil", "Une simple habitude commerciale sans conséquence"], "correct": 1}, {"q": "Face à l'objection de prix, une méthode de traitement rigoureuse consiste à :", "opts": ["Ignorer l'objection et changer de sujet", "Accueillir, reformuler, répondre par un fait, puis valider que l'objection est levée", "Baisser immédiatement le prix sans justification"], "correct": 1}, {"q": "La technique d'instauration du doute sur une couverture existante doit s'appuyer sur :", "opts": ["Des impressions générales sur le marché", "Des faits vérifiables propres au contrat du client", "Une comparaison avec des concurrents non nommés"], "correct": 1}, {"q": "Reformuler les besoins et la solution retenue avant de conclure permet notamment de :", "opts": ["Gagner du temps sans autre bénéfice", "Vérifier l'adhésion réelle du client et sécuriser la traçabilité du conseil", "Éviter de répondre aux dernières objections"], "correct": 1}, {"q": "Une conclusion obtenue par une pression commerciale excessive expose notamment à :", "opts": ["Une fidélisation accrue du client", "Un risque de rétractation et un manquement au devoir de conseil", "Aucune conséquence particulière"], "correct": 1}, {"q": "Le discours de conclusion doit-il être identique pour une redirection tracée et une ressaisie manuelle ?", "opts": ["Oui, toujours identique", "Non, il doit être adapté à chaque cas, en toute transparence", "Cela n'a pas d'importance pour le client"], "correct": 1}, {"q": "Le ciblage d'une campagne d'appels sortants doit distinguer :", "opts": ["Les établissements des prospects", "Les hommes des femmes uniquement", "Les clients riches des autres"], "correct": 0}, {"q": "La construction d'un script d'appel doit suivre une progression allant de :", "opts": ["La conclusion vers l'accroche", "L'accroche vers la qualification puis la découverte", "La découverte vers l'accroche"], "correct": 1}, {"q": "Au téléphone, pour compenser l'absence de langage corporel, le conseiller doit s'appuyer davantage sur :", "opts": ["Le ton et une reformulation plus fréquente", "Le silence uniquement, sans jamais parler", "Un débit de parole très rapide"], "correct": 0}, {"q": "Finaliser un appel de prospection implique systématiquement :", "opts": ["De raccrocher sans engagement précis", "D'engager un prochain pas concret et de consigner l'issue dans le CRM", "De rappeler immédiatement une seconde fois"], "correct": 1}]}$map$::jsonb) m(key, val) on m.key = elem->>'id'
  )
)
where id = 'b991479a-6506-4093-a2e0-baf5ff6085d7';
